// JSON aus der LLM-Antwort extrahieren (robust gegen Codefences/Fließtext)
const raw = $input.first().json.choices[0].message.content;
const parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)[0]);
return [{ json: {
	query: $('Eingang').first().json.query,
	iteration: 1,
	subQueries: parsed.subQueries.slice(0, 4),
} }];

// Rerank-Ausgaben den Teilfragen zuordnen. Gruppen folgen der Reihenfolge der
// Retrieval-Items, Gruppengröße = Anzahl der Punkte des jeweiligen Retrievals
const retrievals = $('Hybrid Retrieval I1').all();
const subs = $('Teilfragen aufteilen I1').all().map(i => i.json.subQuery);
const flat = $input.all().map(i => i.json);
let pos = 0;
const collected = [];
for (let s = 0; s < retrievals.length; s++) {
	const points = retrievals[s].json.result.points;
	const group = flat.slice(pos, pos + points.length);
	pos += points.length;
	for (const r of group.slice(0, 10)) {
		const p = points[r.index];
		collected.push({
			chunkId: p.id, rerankScore: r.score, subQuery: subs[s], iteration: 1,
			text: p.payload.text, source: p.payload.source, title: p.payload.title,
			docId: p.payload.doc_id,
			headingPath: Array.isArray(p.payload.heading_path) ? p.payload.heading_path.join(" > ") : p.payload.heading_path,
			pageNumber: p.payload.page_number,
		});
	}
}
// Deduplikation per chunkID, beste Score-Instanz gewinnt, Herkunft bleibt erhalten
const byId = new Map();
for (const c of collected) {
	const e = byId.get(c.chunkId);
	if (!e || c.rerankScore > e.rerankScore) byId.set(c.chunkId, c);
}
const state = $('Teilfragen parsen I1').first().json;
return [{ json: { ...state, collected: [...byId.values()] } }];

const raw = $input.first().json.choices[0].message.content;
const verdict = JSON.parse(raw.match(/\{[\s\S]*\}/)[0]);
const state = $('Sammeln I1').first().json;
return [{ json: { ...state, sufficient: verdict.sufficient === true, missing: verdict.missing || "" } }];

const raw = $input.first().json.choices[0].message.content;
const parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)[0]);
const state = $('Suffizienz parsen I1').first().json;
const newSubQueries = parsed.subQueries.slice(0, 2);
return [{ json: { ...state, iteration: 2, newSubQueries, subQueries: [...state.subQueries, ...newSubQueries] } }];

const retrievals = $('Hybrid Retrieval I2').all();
const subs = $('Teilfragen aufteilen I2').all().map(i => i.json.subQuery);
const flat = $input.all().map(i => i.json);
let pos = 0;
const collected = [];
for (let s = 0; s < retrievals.length; s++) {
	const points = retrievals[s].json.result.points;
	const group = flat.slice(pos, pos + points.length);
	pos += points.length;
	for (const r of group.slice(0, 10)) {
		const p = points[r.index];
		collected.push({
			chunkId: p.id, rerankScore: r.score, subQuery: subs[s], iteration: 2,
			text: p.payload.text, source: p.payload.source, title: p.payload.title,
			docId: p.payload.doc_id,
			headingPath: Array.isArray(p.payload.heading_path) ? p.payload.heading_path.join(" > ") : p.payload.heading_path,
			pageNumber: p.payload.page_number,
		});
	}
}
// Mit dem bisherigen Stand vereinigen, Dedup per chunkId (beste Score-Instanz)
const state = $('Teilfragen parsen I2').first().json;
const byId = new Map();
for (const c of [...state.collected, ...collected]) {
	const e = byId.get(c.chunkId);
	if (!e || c.rerankScore > e.rerankScore) byId.set(c.chunkId, c);
}
return [{ json: { ...state, collected: [...byId.values()] } }];

