return [{ json: { ...state, collected: [...byId.values()] } }];

// Stop-Grund und finalen Zustand bestimmen, je nachdem, welcher Pfad lief.
// Referenzen auf nicht ausgeführte Nodes werfen einen Fehler → try/catch als Pfad-Detektor.
let state = null, stopReason = null;
try { state = $('Sammeln I3').first().json; stopReason = "Iterationslimit erreicht"; } catch (e) {}
if (!state) {
	try {
		const s2 = $('Suffizienz parsen I2').first().json;
		if (s2.sufficient) { state = s2; stopReason = "Kontext ausreichend nach Iteration 2"; }
	} catch (e) {}
}
if (!state) { state = $('Suffizienz parsen I1').first().json; stopReason = "Kontext ausreichend nach Iteration 1"; }
return [{ json: { ...state, stopReason } }];

// global gegen die Originalfrage geordnet: volle Liste loggen (IR-Metriken),
// bis zu 8 mit Score >= 0.2 als Synthese-Kontext (Budget + Rauschfilter, identisch zu Prototyp 1)
const state = $('Abschluss vorbereiten').first().json;
const ranks = $input.all().map(i => i.json); // [{index, score}] absteigend
const retrieved = ranks.map(r => ({ ...state.collected[r.index], finalScore: r.score })).slice(0,10);
return [{ json: { ...state, retrieved, synthesisChunks: retrieved.filter(c => c.finalScore >= 0.2).slice(0, 8) } }];
